#include <vector>
#include <cmath>
#include <algorithm>

using namespace std;

/**
 * @brief Checks if a number is prime.
 * 
 * A prime number is a natural number greater than 1 that has no positive divisors other than 1 and itself.
 * 
 * @param n The number to check.
 * @return true if n is prime, false otherwise.
 */
bool is_prime(long long n) {
    if (n <= 1) return false;
    if (n <= 3) return true;
    if (n % 2 == 0 || n % 3 == 0) return false;
    for (long long i = 5; i * i <= n; i = i + 6) {
        if (n % i == 0 || n % (i + 2) == 0) return false;
    }
    return true;
}

/**
 * @brief Finds the minimum operations to make the array alternating prime.
 * 
 * @param nums The input array of integers.
 * @return The minimum total operations required.
 */
long long solve(vector<long long> nums) {
    long long total_operations = 0;
    int n = nums.size();

    for (int i = 0; i < n; ++i) {
        long long current_val = nums[i];
        if (i % 2 == 0) {
            // Even index: must be prime
            if (!is_prime(current_val)) {
                // Find the smallest prime >= current_val
                long long target = current_val;
                while (true) {
                    if (is_prime(target)) {
                        total_operations += (target - current_val);
                        break;
                    }
                    target++;
                }
            }
        } else {
            // Odd index: must be non-prime (composite or 1)
            if (is_prime(current_val)) {
                // Find the smallest non-prime >= current_val
                // Since we can only increase, we look for the next non-prime.
                long long target = current_val;
                while (true) {
                    if (!is_prime(target)) {
                        // Special case: 1 is not prime, so if current_val is 2 or 3, the next target might be 4 or 6, etc.
                        // If current_val is 2, next non-prime is 4 (cost 2).
                        // If current_val is 3, next non-prime is 4 (cost 1).
                        total_operations += (target - current_val);
                        break;
                    }
                    target++;
                }
            }
        }
    }

    return total_operations;
}
